mapper.select:
SELECT notice.UN_NO AS un_no , notice.UN_TITLE AS un_title , notice.UN_UIS_CODE AS un_uis_code , institution_master.UIS_NAME AS un_uis_name , notice.UN_AM_USERID AS un_am_userid , DATE_FORMAT(notice.UN_REGDATE, '%Y-%m-%d %H:%i:%s') AS un_regdate FROM TBL_NOTICE notice LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON notice.UN_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND notice.UN_USEYN = 'N' AND notice.UN_NOTICE_TYPE = 'N'
AND notice.UN_UIS_CODE = #{searchUisCode}
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND notice.UN_REGDATE >= STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d %H:%i:%s')
AND notice.UN_REGDATE <= STR_TO_DATE(#{searchEndDate}, '%Y-%m-%d %H:%i:%s')
ORDER BY notice.${sortField1}
ORDER BY notice.UN_REGDATE DESC
LIMIT #{pagenum}, #{pageSize}

SELECT hope.UHP_CODE AS h_uhp_code , institution_master.UIS_NAME AS h_uis_name , CASE WHEN (SELECT COUNT(*) FROM TBL_INSTITUTION_CONTRACT WHERE uic_uis_code = institution_master.uis_code AND uic_complete_yn = 'N' LIMIT 1) = 0 THEN 'Y' ELSE 'N' END AS h_uis_complete_flag , hope.UHP_UIS_CODE AS h_uis_code , member.UM_USERID AS h_um_userid , hope.UHP_TITLE AS h_title , hope.UHP_CONTENT AS h_content , hope.UHP_AUTHOR AS h_author , hope.UHP_PUBLISHER AS h_publisher , hope.UHP_PUBLISHDATE AS h_publishdate , hope.UHP_STATE_FLAG AS h_state_flag , hope.UHP_EBOOK_ISBN AS h_ebook_isbn , hope.UHP_COVER_URL AS h_cover_url , hope.UHP_STATE_FLAG AS h_state_flag , hope.UHP_STATE_MESSAGE AS h_state_message , DATE_FORMAT(hope.UHP_REGDATE, '%Y-%m-%d %H:%i:%s') AS h_regdate , COUNT(hope.UHP_EBOOK_ISBN) AS h_book_count , hope.UHP_ISBN_TYPE AS h_isbn_type FROM TBL_HOPEBOOK_PROPOSAL hope JOIN TBL_INSTITUTION_MASTER institution_master ON hope.UHP_UIS_CODE = institution_master.UIS_CODE JOIN TBL_B2B_MEMBER_MASTER member ON member.UM_CODE = hope.UHP_UM_CODE WHERE 1 = 1
AND hope.UHP_UIS_CODE = #{searchUisCode}
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND hope.UHP_TITLE LIKE CONCAT('%', #{searchName2}, '%')
AND hope.UHP_STATE_FLAG = #{status}
AND STR_TO_DATE(hope.UHP_REGDATE, '%Y-%m-%d') >= STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d')
AND STR_TO_DATE(hope.UHP_REGDATE, '%Y-%m-%d') <= STR_TO_DATE(#{searchEndDate}, '%Y-%m-%d')
GROUP BY hope.UHP_EBOOK_ISBN
ORDER BY hope.${sortField1}
ORDER BY hope.UHP_REGDATE DESC
LIMIT #{pagenum}, #{pageSize}

SELECT hope.UHP_CODE AS h_uhp_code , hope.UHP_COVER_URL AS h_cover_url , hope.UHP_TITLE AS h_title , hope.UHP_AUTHOR AS h_author , hope.UHP_PUBLISHER AS h_publisher , DATE_FORMAT(hope.UHP_PUBLISHDATE, '%Y-%m-%d') AS h_publishdate , hope.UHP_STATE_FLAG AS h_state_flag , hope.UHP_EBOOK_ISBN AS h_ebook_isbn , hope.UHP_STATE_MESSAGE AS h_state_message FROM TBL_HOPEBOOK_PROPOSAL hope LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON hope.UHP_UIS_CODE = institution_master.UIS_CODE WHERE hope.UHP_EBOOK_ISBN = #{h_ebook_isbn}
AND hope.UHP_UIS_CODE = #{h_uis_code}
GROUP BY hope.UHP_EBOOK_ISBN

