mapper.select:
SELECT notice.UN_NO AS un_no , notice.UN_TITLE AS un_title , notice.UN_UIS_CODE AS un_uis_code , institution_master.UIS_NAME AS un_uis_name , notice.UN_AM_USERID AS un_am_userid , DATE_FORMAT(notice.UN_REGDATE, '%Y-%m-%d %H:%i:%s') AS un_regdate , notice.UN_DISPLAY_STARTDATE AS un_display_startdate , notice.UN_DISPLAY_ENDDATE AS un_display_enddate FROM TBL_NOTICE notice LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON notice.UN_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND notice.UN_USEYN = 'N' AND notice.UN_NOTICE_TYPE = 'P'
AND notice.UN_UIS_CODE = #{searchUisCode}
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND notice.UN_REGDATE >= STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d %H:%i:%s')
AND notice.UN_REGDATE <= STR_TO_DATE(#{searchEndDate}, '%Y-%m-%d %H:%i:%s')
ORDER BY notice.${sortField1}
ORDER BY notice.UN_REGDATE DESC
LIMIT #{pagenum}, #{pageSize}

SELECT GROUP_CONCAT(institution_master.UIS_NAME) AS h_uis_name , GROUP_CONCAT(institution_master.UIS_USEYN) AS h_uis_useyn , GROUP_CONCAT(member.UM_USERID) AS h_um_userid , DATE_FORMAT(hope.UHP_REGDATE, '%Y-%m-%d') AS h_regdate , hope.UHP_CONTENT AS h_content , COUNT(hope.UHP_EBOOK_ISBN) AS h_book_count , hope.UHP_EBOOK_ISBN AS h_ebook_isbn , CASE WHEN hope.UHP_ISBN_TYPE = 'E' THEN '전자책' ELSE '종이책' END AS h_isbn_type , hope.UHP_TITLE AS h_title , hope.UHP_AUTHOR AS h_author , hope.UHP_PUBLISHER AS h_publisher , DATE_FORMAT(hope.UHP_PUBLISHDATE, '%Y-%m-%d') AS h_publishdate , CASE WHEN hope.UHP_STATE_FLAG = 'F' THEN '수급실패' WHEN hope.UHP_STATE_FLAG = 'Y' THEN '수급완료' WHEN hope.UHP_STATE_FLAG = 'N' THEN '처리중' ELSE '' END AS h_state_flag , hope.UHP_STATE_MESSAGE AS h_state_message FROM TBL_HOPEBOOK_PROPOSAL hope JOIN TBL_INSTITUTION_MASTER institution_master ON hope.UHP_UIS_CODE = institution_master.UIS_CODE JOIN TBL_B2B_MEMBER_MASTER member ON member.UM_CODE = hope.UHP_UM_CODE WHERE 1 = 1
AND hope.UHP_UIS_CODE = #{searchUisCode}
AND institution_master.UIS_NAME LIKE CONCAT('%', #{searchName}, '%')
AND hope.UHP_TITLE LIKE CONCAT('%', #{searchName2}, '%')
AND hope.UHP_STATE_FLAG = #{status}
AND STR_TO_DATE(hope.UHP_REGDATE, '%Y-%m-%d') >= STR_TO_DATE(#{searchStartDate}, '%Y-%m-%d')
AND STR_TO_DATE(hope.UHP_REGDATE, '%Y-%m-%d') <= STR_TO_DATE(#{searchEndDate}, '%Y-%m-%d')
GROUP BY hope.UHP_EBOOK_ISBN
ORDER BY hope.${sortField1}
ORDER BY hope.UHP_REGDATE DESC
LIMIT #{pagenum}, #{pageSize}
